type MarketSort =
  | "symbol"
  | "lastPrice"
  | "change"
  | "volume"
  | "openInterest"
  | "funding";
type SortDirection = "asc" | "desc";
type MarketFilter = "all" | "community";
type MarketSortPreference = { sort: MarketSort; direction: SortDirection };
type MarketTableLabels = {
  market: string;
  volumeOpenInterest: string;
  priceChange: string;
  lastPrice: string;
  change24h: string;
  volume24h: string;
  openInterest: string;
  estimatedFunding: string;
};

const PERMISSIONLESS_ADMIN_URL =
  "https://admin.orderly.network/permissionless-listing";
const PERMISSIONLESS_LISTING_URL = "https://orderly.network/listing";
const MARKET_SORT_STORAGE_KEY = storageKey("orderlyMarketsSortPreference");
const MARKETS_REFRESH_INTERVAL_MS = 30_000;
const MARKET_SORT_KEYS: MarketSort[] = [
  "symbol",
  "lastPrice",
  "change",
  "volume",
  "openInterest",
  "funding",
];

function numberValue(value: unknown): number {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : 0;
}

type MarketSymbolInfo = Pick<
  FuturesRow,
  "symbol" | "display_symbol_name" | "broker_id"
>;

function stringValue(value: unknown): string {
  return typeof value === "string" ? value.trim() : "";
}

function getDisplaySymbol(market: MarketSymbolInfo): string {
  const displaySymbol = stringValue(market.display_symbol_name);
  if (displaySymbol) return displaySymbol;

  const brokerId = stringValue(market.broker_id);
  if (brokerId && market.symbol.endsWith(`_${brokerId}`)) {
    return market.symbol.slice(0, -(brokerId.length + 1));
  }
  return market.symbol;
}

function getBaseSymbol(market: string | MarketSymbolInfo): string {
  const symbol = typeof market === "string" ? market : getDisplaySymbol(market);
  const parts = symbol.split("_");
  if (parts[0] === "PERP")
    return parts.slice(1, -1).join("_") || parts[1] || symbol;
  return parts[0] || symbol;
}

function isCommunityListed(market: MarketSymbolInfo): boolean {
  return Boolean(stringValue(market.broker_id));
}

function getMarketLogoUrl(market: MarketSymbolInfo): string {
  const logoSymbol = getBaseSymbol(market).toUpperCase();
  const brokerId = stringValue(market.broker_id);
  if (brokerId) {
    return `https://oss.orderly.network/static/broker_symbol_logo/${encodeURIComponent(`${logoSymbol}_${brokerId}`)}.png`;
  }
  return `https://oss.orderly.network/static/symbol_logo/${encodeURIComponent(logoSymbol)}.png`;
}

function formatCompactCurrency(value: number): string {
  if (!Number.isFinite(value)) return "-";
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
    notation: "compact",
    maximumFractionDigits: value >= 1_000_000 ? 2 : 1,
  }).format(value);
}

function formatPrice(value: number): string {
  if (!Number.isFinite(value) || value <= 0) return "-";
  if (value < 0.0001) return "< $0.0001";
  if (value < 1)
    return `$${value.toLocaleString(undefined, { maximumFractionDigits: 6 })}`;
  return `$${value.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
}

function formatPercent(value: number): string {
  if (!Number.isFinite(value)) return "-";
  const sign = value > 0 ? "+" : "";
  return `${sign}${value.toFixed(2)}%`;
}

function formatFundingRate(value: number): string {
  if (!Number.isFinite(value)) return "-";
  return `${(value * 100).toFixed(4)}%`;
}

function formatLeverage(baseImr: unknown): string {
  const imr = numberValue(baseImr);
  if (imr <= 0) return "-";
  const leverage = 1 / imr;
  return `${leverage.toLocaleString(undefined, { maximumFractionDigits: leverage >= 10 ? 1 : 2 })}x`;
}

function formatUtcOffset(date: Date): string {
  const offsetMinutes = -date.getTimezoneOffset();
  if (offsetMinutes === 0) return "UTC";
  const sign = offsetMinutes > 0 ? "+" : "-";
  const absMinutes = Math.abs(offsetMinutes);
  const hours = Math.floor(absMinutes / 60);
  const minutes = absMinutes % 60;
  return minutes === 0
    ? `UTC${sign}${hours}`
    : `UTC${sign}${hours}:${String(minutes).padStart(2, "0")}`;
}

function formatNextFundingTime(value: unknown): string {
  const timestamp = numberValue(value);
  if (!timestamp) return "-";
  const date = new Date(
    timestamp < 1_000_000_000_000 ? timestamp * 1000 : timestamp
  );
  if (Number.isNaN(date.getTime())) return "-";
  return `${date.toLocaleTimeString(undefined, { hour: "2-digit", minute: "2-digit" })} ${formatUtcOffset(date)}`;
}

function getVolume24h(row: FuturesRow): number {
  return numberValue(
    row["24h_amount"] ?? row.amount_24h ?? row["24h_volume"] ?? row.volume_24h
  );
}

function getBaseVolume24h(row: FuturesRow): number {
  return numberValue(row["24h_volume"]);
}

function getOpenInterestNotional(row: FuturesRow): number {
  return numberValue(row.open_interest) * numberValue(row.index_price);
}

function getChange24h(row: FuturesRow): number | null {
  const open = numberValue(row["24h_open"]);
  const close = numberValue(row["24h_close"]);
  if (open <= 0 || close <= 0) return null;
  return ((close - open) / open) * 100;
}

function getDefaultSortDirection(sort: MarketSort): SortDirection {
  return sort === "symbol" ? "asc" : "desc";
}

function isMarketSort(value: unknown): value is MarketSort {
  return (
    typeof value === "string" && MARKET_SORT_KEYS.includes(value as MarketSort)
  );
}

function isSortDirection(value: unknown): value is SortDirection {
  return value === "asc" || value === "desc";
}

function getStoredMarketSortPreference(): MarketSortPreference {
  const fallback: MarketSortPreference = { sort: "volume", direction: "desc" };
  if (typeof window === "undefined") return fallback;

  try {
    const raw = window.localStorage.getItem(MARKET_SORT_STORAGE_KEY);
    if (!raw) return fallback;
    const parsed = JSON.parse(raw) as {
      sort?: unknown;
      direction?: unknown;
    } | null;
    const sort = isMarketSort(parsed?.sort) ? parsed.sort : fallback.sort;
    const direction = isSortDirection(parsed?.direction)
      ? parsed.direction
      : getDefaultSortDirection(sort);
    return { sort, direction };
  } catch {
    return fallback;
  }
}

function compareNumbers(
  a: number | null,
  b: number | null,
  direction: SortDirection
): number {
  if (a === null && b === null) return 0;
  if (a === null) return 1;
  if (b === null) return -1;
  return direction === "asc" ? a - b : b - a;
}

function sortMarkets(
  rows: FuturesRow[],
  sort: MarketSort,
  direction: SortDirection
): FuturesRow[] {
  const sorted = [...rows];
  if (sort === "symbol") {
    return sorted.sort((a, b) =>
      direction === "asc"
        ? getDisplaySymbol(a).localeCompare(getDisplaySymbol(b))
        : getDisplaySymbol(b).localeCompare(getDisplaySymbol(a))
    );
  }
  if (sort === "lastPrice")
    return sorted.sort((a, b) =>
      compareNumbers(
        numberValue(a["24h_close"]),
        numberValue(b["24h_close"]),
        direction
      )
    );
  if (sort === "change")
    return sorted.sort((a, b) =>
      compareNumbers(getChange24h(a), getChange24h(b), direction)
    );
  if (sort === "funding")
    return sorted.sort((a, b) =>
      compareNumbers(
        numberValue(a.est_funding_rate),
        numberValue(b.est_funding_rate),
        direction
      )
    );
  if (sort === "openInterest")
    return sorted.sort((a, b) =>
      compareNumbers(
        getOpenInterestNotional(a),
        getOpenInterestNotional(b),
        direction
      )
    );
  return sorted.sort((a, b) =>
    compareNumbers(getVolume24h(a), getVolume24h(b), direction)
  );
}

function SortHeader({
  label,
  align = "right",
  sortKey,
  currentSort,
  currentDirection,
  onSort,
}: {
  label: string;
  align?: "left" | "right";
  sortKey: MarketSort;
  currentSort: MarketSort;
  currentDirection: SortDirection;
  onSort: (sort: MarketSort) => void;
}) {
  const active = currentSort === sortKey;
  const Icon = active
    ? currentDirection === "asc"
      ? ArrowUp
      : ArrowDown
    : ArrowUpDown;
  return (
    <button
      type="button"
      onClick={() => onSort(sortKey)}
      className={`inline-flex w-full items-center gap-1 text-xs font-medium transition-colors hover:text-(--fg-primary) ${active ? "text-(--fg-primary)" : "text-(--fg-secondary)"} ${align === "right" ? "justify-end" : "justify-start"}`}
    >
      {label}
      <Icon className={`h-3 w-3 ${active ? "opacity-100" : "opacity-55"}`} />
    </button>
  );
}

function MarketLogo({ market }: { market: FuturesRow }) {
  const base = getBaseSymbol(market);
  const logoSymbol = base.toUpperCase();
  return (
    <div className="relative flex h-7 w-7 shrink-0 items-center justify-center overflow-hidden rounded-full bg-(--bg-brand-subtle) text-[9px] font-bold text-(--fg-brand)">
      <img
        src={getMarketLogoUrl(market)}
        alt=""
        className="absolute inset-0 h-full w-full object-cover"
        onError={event => {
          event.currentTarget.style.display = "none";
        }}
      />
      {logoSymbol.slice(0, 2)}
    </div>
  );
}

function AnimatedStatValue({
  value,
  format,
}: {
  value: number;
  format: (value: number) => string;
}) {
  const [displayValue, setDisplayValue] = useState(value);
  const previousValue = useRef(value);

  useEffect(() => {
    const from = previousValue.current;
    const to = Number.isFinite(value) ? value : 0;
    if (from === to) {
      setDisplayValue(to);
      return;
    }

    let frameId = 0;
    const start = performance.now();
    const duration = 900;

    const tick = (now: number) => {
      const progress = Math.min((now - start) / duration, 1);
      const acceleratingProgress = progress * progress;
      const nextValue = from + (to - from) * acceleratingProgress;
      setDisplayValue(nextValue);
      if (progress < 1) frameId = requestAnimationFrame(tick);
      else previousValue.current = to;
    };

    frameId = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(frameId);
  }, [value]);

  return <>{format(displayValue)}</>;
}

