export default function MarketsPage() {
  const { t } = useTranslation();
  const envConfig = getOrderlyEnvConfig();
  const [markets, setMarkets] = useState<FuturesRow[]>([]);
  const [infoBySymbol, setInfoBySymbol] = useState<
    Record<string, PublicInfoRow>
  >({});
  const [brokerNameById, setBrokerNameById] = useState<Record<string, string>>(
    {}
  );
  const [loading, setLoading] = useState(true);
  const [hasLoadedMarkets, setHasLoadedMarkets] = useState(false);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [search, setSearch] = useState("");
  const [marketFilter, setMarketFilter] = useState<MarketFilter>("all");
  const [sortPreference, setSortPreference] = useState<MarketSortPreference>(
    () => getStoredMarketSortPreference()
  );
  const loadInFlightRef = useRef(false);
  const brokerNameByIdRef = useRef<Record<string, string>>({});
  const { sort, direction: sortDirection } = sortPreference;
  const marketFilterItems: ReadonlyArray<
    OdsSegmentedControlItem<MarketFilter>
  > = [
    { value: "all", label: t("markets.filter.all") },
    { value: "community", label: t("markets.filter.community") },
  ];
  const tableLabels: MarketTableLabels = {
    market: t("markets.table.market"),
    volumeOpenInterest: t("markets.table.volumeOpenInterest"),
    priceChange: t("markets.table.priceChange"),
    lastPrice: t("markets.table.lastPrice"),
    change24h: t("markets.table.change24h"),
    volume24h: t("markets.table.volume24h"),
    openInterest: t("markets.table.openInterest"),
    estimatedFunding: t("markets.table.estimatedFunding"),
  };

  function handleSort(nextSort: MarketSort) {
    setSortPreference(current => {
      if (nextSort === current.sort) {
        return {
          sort: current.sort,
          direction: current.direction === "asc" ? "desc" : "asc",
        };
      }
      return { sort: nextSort, direction: getDefaultSortDirection(nextSort) };
    });
  }

  useEffect(() => {
    if (typeof window === "undefined") return;
    window.localStorage.setItem(
      MARKET_SORT_STORAGE_KEY,
      JSON.stringify(sortPreference)
    );
  }, [sortPreference]);

  const resolveBrokerNames = useCallback(async (rows: FuturesRow[]) => {
    const brokerIds = Array.from(
      new Set(rows.map(row => stringValue(row.broker_id)).filter(Boolean))
    );
    const missingBrokerIds = brokerIds.filter(
      brokerId => !brokerNameByIdRef.current[brokerId]
    );
    if (missingBrokerIds.length === 0) return;

    const results = await Promise.allSettled(
      missingBrokerIds.map(async brokerId => {
        const names = await fetchPublicBrokerNames({ broker_id: brokerId });
        const match = names.find(row => row.broker_id === brokerId) || names[0];
        return [brokerId, stringValue(match?.broker_name) || brokerId] as const;
      })
    );
    const nextBrokerNames = { ...brokerNameByIdRef.current };
    results.forEach(result => {
      if (result.status === "fulfilled")
        nextBrokerNames[result.value[0]] = result.value[1];
    });
    brokerNameByIdRef.current = nextBrokerNames;
    setBrokerNameById(nextBrokerNames);
  }, []);

  const loadMarkets = useCallback(
    async (mode: "initial" | "refresh" = "initial") => {
      if (loadInFlightRef.current) return;
      loadInFlightRef.current = true;
      setError(null);
      if (mode === "initial") setLoading(true);
      else setRefreshing(true);

      try {
        const [rows, infoRows] = await Promise.all([
          fetchPublicFutures(),
          fetchPublicInfo(),
        ]);
        setMarkets(rows);
        setInfoBySymbol(
          Object.fromEntries(infoRows.map(row => [row.symbol, row]))
        );
        setHasLoadedMarkets(true);
        void resolveBrokerNames(rows);
      } catch (err) {
        setError(
          err instanceof Error ? err.message : t("markets.errorLoadInfo")
        );
        if (mode === "initial") {
          setMarkets([]);
          setInfoBySymbol({});
        }
      } finally {
        loadInFlightRef.current = false;
        setLoading(false);
        setRefreshing(false);
      }
    },
    [resolveBrokerNames]
  );

  useEffect(() => {
    void loadMarkets();
    const intervalId = window.setInterval(() => {
      if (document.visibilityState === "hidden") return;
      void loadMarkets("refresh");
    }, MARKETS_REFRESH_INTERVAL_MS);

    return () => window.clearInterval(intervalId);
  }, [envConfig.apiBaseUrl, loadMarkets]);

  const filteredMarkets = useMemo(() => {
    const query = search.trim().toLowerCase();
    const scopedRows =
      marketFilter === "community"
        ? markets.filter(isCommunityListed)
        : markets;
    const rows = query
      ? scopedRows.filter(market => {
          const base = getBaseSymbol(market).toLowerCase();
          const displaySymbol = getDisplaySymbol(market).toLowerCase();
          const brokerId = stringValue(market.broker_id);
          const brokerName = brokerNameById[brokerId]?.toLowerCase() || "";
          return (
            base.includes(query) ||
            displaySymbol.includes(query) ||
            market.symbol.toLowerCase().includes(query) ||
            brokerId.toLowerCase().includes(query) ||
            brokerName.includes(query)
          );
        })
      : scopedRows;
    return sortMarkets(rows, sort, sortDirection);
  }, [brokerNameById, marketFilter, markets, search, sort, sortDirection]);

  const hasCommunityListedMarkets = useMemo(
    () => markets.some(isCommunityListed),
    [markets]
  );

  useEffect(() => {
    if (!hasCommunityListedMarkets && marketFilter === "community") {
      setMarketFilter("all");
    }
  }, [hasCommunityListedMarkets, marketFilter]);

  const stats = useMemo(() => {
    const totalVolume = markets.reduce(
      (sum, row) => sum + getVolume24h(row),
      0
    );
    const totalOpenInterest = markets.reduce(
      (sum, row) => sum + getOpenInterestNotional(row),
      0
    );
    return { totalVolume, totalOpenInterest };
  }, [markets]);

  return (
    <div className="min-h-screen bg-(--bg-base)">
      <main>
        <section className="relative overflow-hidden px-6 py-12 sm:py-16">
          <div className="pointer-events-none absolute inset-0 bg-[radial-gradient(ellipse_at_top,var(--bg-brand-subtle),transparent_58%)]" />
          <div className="relative mx-auto max-w-[1100px]">
            <div className="max-w-[760px]">
              <h1 className="max-w-[720px] text-4xl font-semibold leading-tight text-(--fg-primary) sm:text-5xl">
                {t("markets.heroTitle")}
              </h1>
              <p className="mt-5 max-w-[680px] text-base leading-7 text-(--fg-secondary)">
                {t("markets.heroDescription")}
              </p>
              <div className="mt-7 flex flex-wrap items-center gap-3">
                <OdsButton
                  asChild
                  className="gap-2"
                  size="large"
                  variant="highlight"
                >
                  <a href="#markets">
                    {t("markets.viewMarkets")}
                    <ArrowRight className="h-4 w-4" />
                  </a>
                </OdsButton>
                <OdsButton
                  asChild
                  className="gap-2"
                  size="large"
                  variant="secondary"
                >
                  <a
                    href={PERMISSIONLESS_LISTING_URL}
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    {t("markets.exploreListing")}
                    <ArrowRight className="h-4 w-4" />
                  </a>
                </OdsButton>
              </div>
            </div>
          </div>
        </section>

        <section
          id="permissionless-listing"
          className="scroll-mt-24 px-6 pb-12"
        >
          <div className="mx-auto grid max-w-[1100px] gap-4 md:grid-cols-3">
            <OdsMetricCard
              label={t("markets.totalMarkets")}
              loading={!hasLoadedMarkets}
              value={
                <AnimatedStatValue
                  value={markets.length}
                  format={value => Math.round(value).toLocaleString()}
                />
              }
            />
            <OdsMetricCard
              label={t("markets.table.volume24h")}
              loading={!hasLoadedMarkets}
              value={
                <AnimatedStatValue
                  value={stats.totalVolume}
                  format={formatCompactCurrency}
                />
              }
            />
            <OdsMetricCard
              label={t("markets.table.openInterest")}
              loading={!hasLoadedMarkets}
              value={
                <AnimatedStatValue
                  value={stats.totalOpenInterest}
                  format={formatCompactCurrency}
                />
              }
            />
          </div>
        </section>

        <section className="px-6 pb-12">
          <div className="mx-auto max-w-[1100px] rounded-2xl border border-(--line-subtle) bg-(--bg-surface-primary) p-5 sm:p-6">
            <div className="flex flex-col gap-5 lg:flex-row lg:items-center lg:justify-between">
              <div className="max-w-[720px]">
                <div className="flex flex-wrap items-center gap-2">
                  <OdsBadge type="brand">
                    {t("markets.permissionlessListing")}
                  </OdsBadge>
                </div>
                <h2 className="mt-3 text-2xl font-semibold text-(--fg-primary) sm:text-3xl">
                  {t("markets.listMarketTitle")}
                </h2>
                <p className="mt-2 text-sm leading-6 text-(--fg-secondary)">
                  {t("markets.listMarketDescription")}
                </p>
                <div className="mt-4 flex flex-wrap gap-2 text-xs font-medium text-(--fg-secondary)">
                  <OdsBadge type="subtle">
                    {t("markets.noManualListingQueue")}
                  </OdsBadge>
                  <OdsBadge type="subtle">
                    {t("markets.customOracleSupport")}
                  </OdsBadge>
                  <OdsBadge type="subtle">
                    {t("markets.isolatedMargin")}
                  </OdsBadge>
                </div>
              </div>
              <div className="flex shrink-0 flex-wrap gap-3">
                <OdsButton
                  asChild
                  className="gap-2"
                  size="large"
                  variant="highlight"
                >
                  <a
                    href={PERMISSIONLESS_ADMIN_URL}
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    {t("markets.launchMarket")}
                    <ExternalLink className="h-4 w-4" />
                  </a>
                </OdsButton>
                <OdsButton
                  asChild
                  className="gap-2"
                  size="large"
                  variant="secondary"
                >
                  <a
                    href={PERMISSIONLESS_LISTING_URL}
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    {t("markets.learnHowItWorks")}
                    <ArrowRight className="h-4 w-4" />
                  </a>
                </OdsButton>
              </div>
            </div>
          </div>
        </section>

        <section id="markets" className="scroll-mt-24 px-6 pb-20">
          <div className="mx-auto max-w-[1100px] rounded-2xl border border-(--line-subtle) bg-(--bg-surface-primary)">
            <div className="flex flex-col gap-4 border-b border-(--line-subtle) p-4 lg:flex-row lg:items-center lg:justify-between">
              <div>
                <h2 className="text-xl font-semibold text-(--fg-primary)">
                  {t("markets.liveMarketInfo")}
                </h2>
                <p className="mt-1 text-sm text-(--fg-secondary)">
                  {t("markets.liveMarketDescription")}
                </p>
              </div>
              <OdsInput
                className="rounded-xl border-(--line-subtle) focus-within:border-(--line-brand)"
                containerClassName="w-full max-w-md lg:w-[360px]"
                onChange={event => setSearch(event.target.value)}
                placeholder={t("markets.searchPlaceholder")}
                prefix={<Search className="h-4 w-4" />}
                type="text"
                value={search}
              />
            </div>

            <div
              className={`flex flex-col gap-3 border-b border-(--line-subtle) p-4 sm:flex-row sm:items-center ${hasCommunityListedMarkets ? "sm:justify-between" : "sm:justify-end"}`}
            >
              {hasCommunityListedMarkets && (
                <OdsSegmentedControl
                  ariaLabel={t("markets.marketFilter")}
                  items={marketFilterItems}
                  onValueChange={setMarketFilter}
                  value={marketFilter}
                />
              )}
              <div className="flex items-center gap-3">
                <span className="text-xs text-(--fg-secondary)">
                  {refreshing
                    ? t("markets.updatingLatestData")
                    : t("markets.autoUpdates", {
                        seconds: MARKETS_REFRESH_INTERVAL_MS / 1000,
                      })}
                </span>
                <button
                  type="button"
                  onClick={() => void loadMarkets("refresh")}
                  disabled={loading || refreshing}
                  className="inline-flex w-fit items-center gap-2 rounded-full border border-(--line-subtle) px-3 py-1.5 text-xs font-semibold text-(--fg-secondary) transition-colors hover:bg-(--bg-hover) hover:text-(--fg-primary) disabled:cursor-not-allowed disabled:opacity-60"
                >
                  <RefreshCw
                    className={`h-3.5 w-3.5 ${loading || refreshing ? "animate-spin" : ""}`}
                  />
                  {t("common.refresh")}
                </button>
              </div>
            </div>

            {error && (
              <OdsAlert className="m-4" type="negative">
                {error}
              </OdsAlert>
            )}

            {loading && !hasLoadedMarkets ? (
              <MarketTableSkeleton labels={tableLabels} />
            ) : filteredMarkets.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-20 text-center">
                <p className="text-sm text-(--fg-secondary)">
                  {marketFilter === "community"
                    ? t("markets.noCommunityMarkets")
                    : t("markets.noMarkets")}
                </p>
                {search && (
                  <button
                    type="button"
                    onClick={() => setSearch("")}
                    className="mt-2 text-sm font-medium text-(--fg-brand) hover:underline"
                  >
                    {t("markets.clearSearch")}
                  </button>
                )}
              </div>
            ) : (
              <div className="overflow-hidden">
                <table className="w-full table-fixed lg:hidden">
                  <thead>
                    <tr className="border-b border-(--line-subtle)">
                      <th className="w-[34%] px-4 py-3 text-left">
                        <SortHeader
                          label={tableLabels.market}
                          align="left"
                          sortKey="symbol"
                          currentSort={sort}
                          currentDirection={sortDirection}
                          onSort={handleSort}
                        />
                      </th>
                      <th className="w-[33%] px-4 py-3 text-right">
                        <SortHeader
                          label={tableLabels.volumeOpenInterest}
                          sortKey="volume"
                          currentSort={sort}
                          currentDirection={sortDirection}
                          onSort={handleSort}
                        />
                      </th>
                      <th className="w-[33%] px-4 py-3 text-right">
                        <SortHeader
                          label={tableLabels.priceChange}
                          sortKey="lastPrice"
                          currentSort={sort}
                          currentDirection={sortDirection}
                          onSort={handleSort}
                        />
                      </th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredMarkets.map(market => {
                      const base = getBaseSymbol(market);
                      const lastPrice = numberValue(market["24h_close"]);
                      const change = getChange24h(market);
                      const changeTone =
                        change === null || change === 0
                          ? "text-(--fg-secondary)"
                          : change > 0
                            ? "text-(--fg-positive)"
                            : "text-(--fg-negative)";
                      const marketInfo = infoBySymbol[market.symbol];
                      const leverageText = formatLeverage(marketInfo?.base_imr);
                      return (
                        <tr
                          key={market.symbol}
                          className="border-b border-(--line-subtle) last:border-b-0 hover:bg-(--bg-hover)"
                        >
                          <td className="px-4 py-4">
                            <div className="flex min-w-0 items-center gap-2">
                              <MarketLogo market={market} />
                              <div className="min-w-0">
                                <div className="flex min-w-0 items-center gap-1.5">
                                  <span className="truncate text-sm font-semibold text-(--fg-primary)">
                                    {base}
                                  </span>
                                  {leverageText !== "-" && (
                                    <OdsBadge type="brand">
                                      {leverageText}
                                    </OdsBadge>
                                  )}
                                </div>
                              </div>
                            </div>
                          </td>
                          <td className="px-4 py-4 text-right text-sm">
                            <div className="truncate font-semibold text-(--fg-primary)">
                              {formatCompactCurrency(getVolume24h(market))}
                            </div>
                            <div className="truncate text-xs text-(--fg-secondary)">
                              OI{" "}
                              {formatCompactCurrency(
                                getOpenInterestNotional(market)
                              )}
                            </div>
                          </td>
                          <td className="px-4 py-4 text-right text-sm">
                            <div className="truncate font-semibold text-(--fg-primary)">
                              {formatPrice(lastPrice)}
                            </div>
                            {change === null ? (
                              <div className="text-xs text-(--fg-secondary)">
                                -
                              </div>
                            ) : (
                              <div
                                className={`inline-flex items-center justify-end gap-1 text-xs font-semibold ${changeTone}`}
                              >
                                {change > 0 ? (
                                  <ArrowUp className="h-3 w-3" />
                                ) : change < 0 ? (
                                  <ArrowDown className="h-3 w-3" />
                                ) : null}
                                {formatPercent(change)}
                              </div>
                            )}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>

                <table className="hidden w-full table-fixed lg:table">
                  <thead>
                    <tr className="border-b border-(--line-subtle)">
                      <th className="w-[34%] px-4 py-3 text-left">
                        <SortHeader
                          label={tableLabels.market}
                          align="left"
                          sortKey="symbol"
                          currentSort={sort}
                          currentDirection={sortDirection}
                          onSort={handleSort}
                        />
                      </th>
                      <th className="w-[14%] px-4 py-3 text-right">
                        <SortHeader
                          label={tableLabels.lastPrice}
                          sortKey="lastPrice"
                          currentSort={sort}
                          currentDirection={sortDirection}
                          onSort={handleSort}
                        />
                      </th>
                      <th className="w-[13%] px-4 py-3 text-right">
                        <SortHeader
                          label={tableLabels.change24h}
                          sortKey="change"
                          currentSort={sort}
                          currentDirection={sortDirection}
                          onSort={handleSort}
                        />
                      </th>
                      <th className="w-[16%] px-4 py-3 text-right">
                        <SortHeader
                          label={tableLabels.volume24h}
                          sortKey="volume"
                          currentSort={sort}
                          currentDirection={sortDirection}
                          onSort={handleSort}
                        />
                      </th>
                      <th className="w-[13%] px-4 py-3 text-right">
                        <SortHeader
                          label={tableLabels.openInterest}
                          sortKey="openInterest"
                          currentSort={sort}
                          currentDirection={sortDirection}
                          onSort={handleSort}
                        />
                      </th>
                      <th className="w-[10%] px-4 py-3 text-right">
                        <SortHeader
                          label={tableLabels.estimatedFunding}
                          sortKey="funding"
                          currentSort={sort}
                          currentDirection={sortDirection}
                          onSort={handleSort}
                        />
                      </th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredMarkets.map(market => {
                      const base = getBaseSymbol(market);
                      const displaySymbol = getDisplaySymbol(market);
                      const brokerId = stringValue(market.broker_id);
                      const lastPrice = numberValue(market["24h_close"]);
                      const change = getChange24h(market);
                      const changeTone =
                        change === null || change === 0
                          ? "text-(--fg-secondary)"
                          : change > 0
                            ? "text-(--fg-positive)"
                            : "text-(--fg-negative)";
                      const marketInfo = infoBySymbol[market.symbol];
                      const nextFundingTime = formatNextFundingTime(
                        market.next_funding_time
                      );
                      const fundingRateValue = numberValue(
                        market.est_funding_rate
                      );
                      const fundingRate = formatFundingRate(fundingRateValue);
                      const fundingTone =
                        fundingRateValue === 0
                          ? "text-(--fg-primary)"
                          : fundingRateValue > 0
                            ? "text-gradient-positive"
                            : "text-gradient-negative";
                      const leverageText = formatLeverage(marketInfo?.base_imr);
                      const brokerName = brokerNameById[brokerId] || brokerId;
                      return (
                        <tr
                          key={market.symbol}
                          className="border-b border-(--line-subtle) last:border-b-0 hover:bg-(--bg-hover)"
                        >
                          <td className="px-4 py-4">
                            <div className="flex items-center gap-2.5">
                              <MarketLogo market={market} />
                              <div className="min-w-0">
                                <div className="flex items-center gap-2">
                                  <span className="truncate text-sm font-semibold text-(--fg-primary)">
                                    {base}
                                  </span>
                                  {brokerId && (
                                    <OdsBadge type="brand">
                                      {t("markets.communityListed")}
                                    </OdsBadge>
                                  )}
                                  {leverageText !== "-" && (
                                    <OdsBadge type="brand">
                                      {leverageText}
                                    </OdsBadge>
                                  )}
                                </div>
                                <div className="mt-1 flex flex-wrap items-center gap-2 text-xs text-(--fg-secondary)">
                                  <span className="truncate">
                                    {displaySymbol}
                                  </span>
                                  {brokerId && (
                                    <LocalizedLink
                                      to={`/board/${encodeURIComponent(brokerId)}`}
                                      title={t("markets.brokerIdTitle", {
                                        brokerId,
                                      })}
                                      className="inline-flex h-[20px] max-w-[120px] items-center justify-center truncate rounded-lg bg-(--bg-tabs) px-2 text-[12px] font-medium leading-[120%] text-(--fg-secondary) transition-colors hover:bg-(--bg-hover) hover:text-(--fg-primary)"
                                    >
                                      {brokerName}
                                    </LocalizedLink>
                                  )}
                                </div>
                              </div>
                            </div>
                          </td>
                          <td className="px-4 py-4 text-right text-sm">
                            <div className="font-semibold text-(--fg-primary)">
                              {formatPrice(lastPrice)}
                            </div>
                          </td>
                          <td className="px-4 py-4 text-right">
                            {change === null ? (
                              <span className="text-sm text-(--fg-secondary)">
                                -
                              </span>
                            ) : (
                              <span
                                className={`inline-flex items-center justify-end gap-1 text-sm font-semibold ${changeTone}`}
                              >
                                {change > 0 ? (
                                  <ArrowUp className="h-3.5 w-3.5" />
                                ) : change < 0 ? (
                                  <ArrowDown className="h-3.5 w-3.5" />
                                ) : null}
                                {formatPercent(change)}
                              </span>
                            )}
                          </td>
                          <td className="px-4 py-4 text-right text-sm">
                            <div className="font-semibold text-(--fg-primary)">
                              {formatCompactCurrency(getVolume24h(market))}
                            </div>
                            <div className="text-xs text-(--fg-secondary)">
                              {getBaseVolume24h(market).toLocaleString(
                                undefined,
                                { maximumFractionDigits: 2 }
                              )}{" "}
                              {base}
                            </div>
                          </td>
                          <td className="px-4 py-4 text-right text-sm">
                            <div className="font-semibold text-(--fg-primary)">
                              {formatCompactCurrency(
                                getOpenInterestNotional(market)
                              )}
                            </div>
                            <div className="text-xs text-(--fg-secondary)">
                              {numberValue(market.open_interest).toLocaleString(
                                undefined,
                                { maximumFractionDigits: 2 }
                              )}{" "}
                              {base}
                            </div>
                          </td>
                          <td className="px-4 py-4 text-right text-sm">
                            <div className={`font-semibold ${fundingTone}`}>
                              {fundingRate}
                            </div>
                            <div className="text-xs text-(--fg-secondary)">
                              {nextFundingTime === "-"
                                ? "-"
                                : t("markets.atTime", {
                                    time: nextFundingTime,
                                  })}
                            </div>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </section>
      </main>

      <footer className="border-t border-(--line-subtle) px-6 py-8">
        <div className="mx-auto flex max-w-[1100px] flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          <div className="flex items-center gap-2 text-sm text-(--fg-secondary)">
            <OrderlyLogo className="h-5 w-5" />
            <span>Orderly One</span>
          </div>
          <div className="text-sm text-(--fg-secondary)">
            {t("markets.footerPoweredBy")}
          </div>
        </div>
      </footer>
    </div>
  );
}
